<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Kanban Board</title>
<style>
  *, *::before, *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
  }

  body {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    background: #1a1d23;
    color: #e0e0e0;
    min-height: 100vh;
    padding: 2rem;
  }

  h1 {
    text-align: center;
    font-size: 1.8rem;
    font-weight: 600;
    margin-bottom: 2rem;
    color: #ffffff;
    letter-spacing: -0.5px;
  }

  .board {
    display: flex;
    gap: 1.5rem;
    max-width: 1200px;
    margin: 0 auto;
    align-items: flex-start;
  }

  .column {
    flex: 1;
    background: #24272e;
    border-radius: 12px;
    padding: 1rem;
    min-height: 300px;
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
    transition: background-color 0.2s ease;
  }

  .column.drag-over {
    background: #2a2e38;
    outline: 2px dashed #4a9eff;
    outline-offset: -2px;
  }

  .col-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding-bottom: 0.75rem;
    border-bottom: 1px solid #333640;
  }

  .col-title {
    font-size: 0.95rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }

  .count {
    background: #333640;
    color: #aaa;
    font-size: 0.75rem;
    font-weight: 600;
    padding: 0.2rem 0.55rem;
    border-radius: 999px;
    min-width: 1.4em;
    text-align: center;
  }

  .card-container {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 0.6rem;
    min-height: 50px;
  }

  .card {
    background: #2e3139;
    border-radius: 8px;
    padding: 0.75rem 0.9rem;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.6rem;
    cursor: grab;
    user-select: none;
    transition: transform 0.12s ease, box-shadow 0.12s ease, opacity 0.12s ease;
    border: 1px solid #383b45;
  }

  .card:hover {
    transform: translateY(-1px);
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.3);
  }

  .card.dragging {
    opacity: 0.4;
    transform: scale(0.97);
  }

  .card-title {
    flex: 1;
    font-size: 0.9rem;
    line-height: 1.35;
    word-break: break-word;
  }

  .card-del {
    background: none;
    border: none;
    color: #666;
    cursor: pointer;
    font-size: 1.1rem;
    padding: 0.15rem 0.35rem;
    border-radius: 4px;
    line-height: 1;
    transition: color 0.15s ease, background-color 0.15s ease;
    flex-shrink: 0;
  }

  .card-del:hover {
    color: #ff6b6b;
    background-color: rgba(255, 107, 107, 0.1);
  }

  .add-bar {
    max-width: 1200px;
    margin: 0 auto 1.5rem;
    display: flex;
    gap: 0.6rem;
  }

  #new-card {
    flex: 1;
    padding: 0.7rem 1rem;
    border-radius: 8px;
    border: 1px solid #383b45;
    background: #24272e;
    color: #e0e0e0;
    font-size: 0.9rem;
    outline: none;
    transition: border-color 0.2s ease;
  }

  #new-card:focus {
    border-color: #4a9eff;
  }

  #new-card::placeholder {
    color: #555;
  }

  #add-card {
    padding: 0.7rem 1.4rem;
    border-radius: 8px;
    border: none;
    background: #4a9eff;
    color: #fff;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    transition: background-color 0.15s ease;
    white-space: nowrap;
  }

  #add-card:hover {
    background: #3a8eef;
  }

  @media (max-width: 768px) {
    body { padding: 1rem; }
    .board { flex-direction: column; }
    .column { min-height: auto; }
  }
</style>
</head>
<body>

<h1>Kanban Board</h1>

<div class="add-bar">
  <input type="text" id="new-card" placeholder="Add a new task…" autocomplete="off">
  <button id="add-card">Add Task</button>
</div>

<div class="board">
  <div class="column" id="col-todo">
    <div class="col-header">
      <span class="col-title">To Do</span>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>

  <div class="column" id="col-doing">
    <div class="col-header">
      <span class="col-title">Doing</span>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>

  <div class="column" id="col-done">
    <div class="col-header">
      <span class="col-title">Done</span>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>
</div>

<script>
(function () {
  "use strict";

  var STORAGE_KEY = "kanban-board-state";
  var columns = ["col-todo", "col-doing", "col-done"];

  /* ---- State ---- */
  function loadState() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (raw) return JSON.parse(raw);
    } catch (_) {}
    return [];
  }

  function saveState(cards) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(cards));
  }

  /* ---- Helpers ---- */
  function nextId() {
    return Date.now().toString(36) + Math.random().toString(36).slice(2, 7);
  }

  function updateCounts() {
    columns.forEach(function (colId) {
      var col = document.getElementById(colId);
      var countEl = col.querySelector(".count");
      var container = col.querySelector(".card-container");
      var n = container.querySelectorAll(".card").length;
      countEl.textContent = String(n);
    });
  }

  function createCardElement(title, id) {
    var card = document.createElement("div");
    card.className = "card";
    card.setAttribute("draggable", "true");
    card.dataset.id = id;

    var titleSpan = document.createElement("span");
    titleSpan.className = "card-title";
    titleSpan.textContent = title;

    var delBtn = document.createElement("button");
    delBtn.className = "card-del";
    delBtn.setAttribute("aria-label", "Delete card");
    delBtn.textContent = "\u00d7";

    card.appendChild(titleSpan);
    card.appendChild(delBtn);

    /* Delete handler */
    delBtn.addEventListener("click", function () {
      var state = loadState();
      state = state.filter(function (c) { return c.id !== id; });
      saveState(state);
      card.remove();
      updateCounts();
    });

    /* Drag start on the card */
    card.addEventListener("dragstart", function (e) {
      card.classList.add("dragging");
      e.dataTransfer.setData("text/plain", id);
      e.dataTransfer.effectAllowed = "move";
    });

    card.addEventListener("dragend", function () {
      card.classList.remove("dragging");
      columns.forEach(function (cid) {
        document.getElementById(cid).classList.remove("drag-over");
      });
    });

    return card;
  }

  function renderBoard() {
    var state = loadState();
    /* Clear all containers */
    columns.forEach(function (colId) {
      var container = document.querySelector("#" + colId + " .card-container");
      container.innerHTML = "";
    });
    /* Re-create cards */
    state.forEach(function (item) {
      var container = document.querySelector("#" + item.column + " .card-container");
      if (container) {
        container.appendChild(createCardElement(item.title, item.id));
      }
    });
    updateCounts();
  }

  /* ---- Add card ---- */
  function addCard() {
    var input = document.getElementById("new-card");
    var text = input.value.trim();
    if (!text) return;

    var id = nextId();
    var state = loadState();
    state.push({ id: id, title: text, column: "col-todo" });
    saveState(state);

    var container = document.querySelector("#col-todo .card-container");
    container.appendChild(createCardElement(text, id));

    input.value = "";
    updateCounts();
  }

  /* ---- Drag & Drop on columns ---- */
  columns.forEach(function (colId) {
    var col = document.getElementById(colId);
    var container = col.querySelector(".card-container");

    col.addEventListener("dragover", function (e) {
      e.preventDefault();
      e.dataTransfer.dropEffect = "move";
      col.classList.add("drag-over");
    });

    col.addEventListener("dragleave", function (e) {
      /* Only remove highlight when leaving the column itself */
      if (!col.contains(e.relatedTarget)) {
        col.classList.remove("drag-over");
      }
    });

    col.addEventListener("drop", function (e) {
      e.preventDefault();
      col.classList.remove("drag-over");

      var cardId = e.dataTransfer.getData("text/plain");
      if (!cardId) return;

      /* Find the card element and move it */
      var allCards = document.querySelectorAll(".card");
      var cardEl = null;
      for (var i = 0; i < allCards.length; i++) {
        if (allCards[i].dataset.id === cardId) {
          cardEl = allCards[i];
          break;
        }
      }
      if (!cardEl) return;

      var targetContainer = col.querySelector(".card-container");
      targetContainer.appendChild(cardEl);

      /* Update state */
      var state = loadState();
      for (var j = 0; j < state.length; j++) {
        if (state[j].id === cardId) {
          state[j].column = colId;
          break;
        }
      }
      saveState(state);
      updateCounts();
    });
  });

  /* ---- Event listeners for add button/input ---- */
  document.getElementById("add-card").addEventListener("click", addCard);

  document.getElementById("new-card").addEventListener("keydown", function (e) {
    if (e.key === "Enter") addCard();
  });

  /* ---- Init ---- */
  renderBoard();
})();
</script>

</body>
</html>
